def create_sequences(data, taille_fenêtre):

    X = []
    y = []

    # on parcourt la série
    for i in range(len(data) - taille_fenêtre):

        # séquence d'entrée
        X.append(data[i:i+taille_fenêtre])

        # valeur à prédire
        y.append(data[i+taille_fenêtre])

    return np.array(X), np.array(y)
